// bytecode_analyzer.h
typedef struct {
  uint32_t instruction_count;
  uint32_t register_count;
  uint32_t memory_usage;
} BytecodeAnalysis;

BytecodeAnalysis analyze_bytecode(const bytecode_t *bc) {
  BytecodeAnalysis analysis = {0};

  for (uint32_t i = 0; i < bc->instruction_count; i++) {
    instruction_t *inst = &bc->instructions[i];

    // 각 명령어의 기계코드 크기 추정
    analysis.instruction_count++;
    analysis.memory_usage += estimate_instruction_size(inst);
  }

  return analysis;
}

// 안전 마진: 1.5배
size_t required_size = analysis.memory_usage * 1.5;
```

**Step 2: 가드 페이지 설정**
```cpp
// memory.h
void *allocate_with_guards(size_t size) {
  // 전체: GUARD_PAGE(4K) + BUFFER(size) + GUARD_PAGE(4K)
  size_t total = PAGE_SIZE + size + PAGE_SIZE;

  void *ptr = mmap(NULL, total, PROT_READ | PROT_WRITE,
                   MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);

  // 가드 페이지를 읽기 전용으로 설정
  mprotect(ptr, PAGE_SIZE, PROT_NONE);                    // 앞
  mprotect((char *)ptr + PAGE_SIZE + size, PAGE_SIZE, PROT_NONE);  // 뒤

  return (char *)ptr + PAGE_SIZE;  // 실제 버퍼 반환
}
```

**Step 3: 경계 검사**
```cpp
// codegen.c
bool write_instruction(codegen_ctx *ctx, const instruction_t *inst) {
  size_t required = estimate_instruction_size(inst);

  // 현재 오프셋 + 필요 크기 > 버퍼 크기 체크
  if (ctx->current_offset + required > ctx->buffer_size) {
    LOG_ERROR("Buffer overflow: offset=%zu, required=%zu, size=%zu",
              ctx->current_offset, required, ctx->buffer_size);
    return false;
  }

  // 안전하게 쓰기
  write_bytes(ctx, inst, required);
  ctx->current_offset += required;
  return true;
}
```

