**Step 1: 헤더 검증**
```cpp
// validation.c
#define BYTECODE_MAGIC 0xFL4NG  // FreeLang
#define BYTECODE_VERSION 4

bool validate_bytecode_header(const bytecode_t *bc) {
  if (bc == NULL) return false;
  if (bc->magic != BYTECODE_MAGIC) {
    LOG_ERROR("Invalid magic: expected 0x%x, got 0x%x",
              BYTECODE_MAGIC, bc->magic);
    return false;
  }
  if (bc->version != BYTECODE_VERSION) {
    LOG_ERROR("Unsupported version: %u", bc->version);
    return false;
  }
  if (bc->flags & ~ALLOWED_FLAGS) {
    LOG_ERROR("Invalid flags: 0x%x", bc->flags);
    return false;
  }
  return true;
}
```

**Step 2: 명령어 화이트리스트**
```cpp
// instructions.h
#define ALLOWED_INSTRUCTIONS { \
  INST_LOAD, INST_STORE, INST_CALL, INST_RET, \
  INST_ADD, INST_SUB, INST_MUL, INST_DIV, \
  INST_JMP, INST_JMPIF, INST_PUSH, INST_POP, \
  INST_NOP, INST_HALT \
}

static const bool allowed_ops[256] = {
  [INST_LOAD] = true,
  [INST_STORE] = true,
  // ... 나머지는 false
};

bool validate_instruction(const instruction_t *inst) {
  if (inst->opcode >= 256) return false;
  if (!allowed_ops[inst->opcode]) {
    LOG_ERROR("Disallowed instruction: 0x%x", inst->opcode);
    return false;
  }
  return true;
}
```

**Step 3: 피연산자 검증**
```cpp
// validation.c
bool validate_operand(const instruction_t *inst, unsigned int idx) {
  if (idx >= MAX_OPERANDS) return false;

  int operand = inst->operands[idx];

  // 범위 검사
  if (operand < 0 || operand >= MAX_OPERANDS) {
    LOG_ERROR("Operand out of range: %d", operand);
    return false;
  }

  // 명령어별 특정 검증
  switch (inst->opcode) {
    case INST_LOAD:
      // 레지스터 인덱스 검증
      if (operand >= NUM_REGISTERS) return false;
      break;
    case INST_JMP:
      // 점프 대상 주소 검증
      if (operand >= MAX_CODE_SIZE) return false;
      break;
  }

  return true;
}

bool validate_all_instructions(const bytecode_t *bc) {
  for (uint32_t i = 0; i < bc->instruction_count; i++) {
    instruction_t *inst = &bc->instructions[i];

    if (!validate_instruction(inst)) return false;

    for (unsigned int j = 0; j < MAX_OPERANDS; j++) {
      if (!validate_operand(inst, j)) return false;
    }
  }
  return true;
}
```

#### 수정 후 효과
- ✅ 악의적 바이트코드 100% 차단
- ✅ 제어 흐름 검증
- ✅ 타입 안전성 강화

