#### 수정 방안

**Step 1: 메모리 권한 분리**
```cpp
// memory.c
void setup_memory_protection() {
  // 코드 섹션: 읽기 + 실행만 (RX)
  mprotect(code_section, code_size, PROT_READ | PROT_EXEC);

  // 데이터 섹션: 읽기 + 쓰기만 (RW)
  mprotect(data_section, data_size, PROT_READ | PROT_WRITE);

  // 스택: 읽기 + 쓰기 (RW)
  // 실행 불가 (NX bit 활성화)
}

// 컴파일 옵션 (gcc/clang)
// -fPIE -pie : 위치독립실행파일 (ASLR 호환)
// -fstack-protector-strong : Stack Canary
// -D_FORTIFY_SOURCE=2 : 추가 보안 검사
```

**Step 2: Stack Canary**
```cpp
// stack.c
#define CANARY_SIZE 8

typedef struct {
  uint64_t canary;
  void *saved_rbp;
  void *saved_rip;
} StackFrame;

// 함수 진입 시
void function_prologue(codegen_ctx *ctx) {
  uint64_t canary = generate_random_canary();

  // 스택에 저장
  write_instruction(ctx, MOV_CANARY_TO_STACK(canary));

  // 컨텍스트에도 저장
  ctx->stack_frames[ctx->frame_count].canary = canary;
}

// 함수 반환 시
void function_epilogue(codegen_ctx *ctx) {
  uint64_t expected = ctx->stack_frames[ctx->frame_count - 1].canary;
  uint64_t actual = read_from_stack();

  if (actual != expected) {
    // 스택이 손상됨 → 프로그램 중단
    LOG_ERROR("Stack canary violation!");
    exit(STACK_CANARY_VIOLATION);
  }
}
```

**Step 3: CFI (제어 흐름 무결성)**
```cpp
// cfi.c
typedef struct {
  void *target_address;
  uint32_t allowed_callers;  // 비트마스크
} CFITarget;

bool verify_call_target(void *target, uint32_t caller_id) {
  CFITarget *cfi = lookup_cfi_metadata(target);

  if (cfi == NULL) {
    LOG_ERROR("Unknown call target: %p", target);
    return false;
  }

  if (!(cfi->allowed_callers & (1 << caller_id))) {
    LOG_ERROR("Unauthorized call from %u to %p", caller_id, target);
    return false;
  }

  return true;
}
```

