```typescript
// src/sandbox/docker-sandbox.ts
import Docker from 'dockerode';

interface SandboxConfig {
  memoryLimit: number;      // 256MB
  cpuQuota: number;         // 0.1 CPU
  timeout: number;          // 5초
  allowedPorts: number[];   // 외부 통신 차단
}

class DockerSandbox {
  private docker: Docker;
  private containerImage = 'freelang-sandbox:latest';

  async executeCode(code: string, config: SandboxConfig): Promise<ExecutionResult> {
    try {
      // 1. 컨테이너 생성
      const container = await this.docker.createContainer({
        Image: this.containerImage,

        // 메모리 제한
        Memory: config.memoryLimit,
        MemorySwap: config.memoryLimit,  // 스왑 비활성화

        // CPU 제한
        CpuQuota: config.cpuQuota,
        CpuPeriod: 100000,

        // 파일 시스템
        ReadonlyRootfs: true,    // 읽기 전용 루트
        Tmpfs: {
          '/tmp': 'size=100m,mode=1777'  // /tmp만 쓰기 가능
        },

        // 네트워크 격리
        NetworkMode: 'none',     // 외부 통신 불가

        // 보안 옵션
        CapDrop: ['ALL'],        // 모든 Linux capabilities 제거
        SecurityOpt: [
          'no-new-privileges:true'  // 새로운 권한 획득 불가
        ],

        // 입력 준비
        StdinOpen: true,
        AttachStdin: true,
        AttachStdout: true,
        AttachStderr: true
      });

      // 2. 코드 작성
      await container.putArchive(code, '/code/');

      // 3. 타임아웃 포함 실행
      const startTime = Date.now();
      const stream = await container.attach({
        stream: true,
        stdout: true,
        stderr: true,
        stdin: true
      });

      // 코드 실행 (컨테이너 내부 안전한 인터프리터)
      const result = await this.runWithTimeout(
        container,
        `/opt/freelang-runner /code/main.fl`,
        config.timeout
      );

      // 4. 정리
      await container.stop();
      await container.remove();

      return {
        success: result.exitCode === 0,
        stdout: result.stdout,
        stderr: result.stderr,
        exitCode: result.exitCode
      };

    } catch (error) {
      return {
        success: false,
        error: `Sandbox execution failed: ${error.message}`,
        stderr: error.message
      };
    }
  }

  private async runWithTimeout(
    container: Docker.Container,
    command: string,
    timeoutMs: number
  ): Promise<{ exitCode: number; stdout: string; stderr: string }> {
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => {
        container.kill().catch(() => {});
        reject(new Error(`Execution timeout (${timeoutMs}ms)`));
      }, timeoutMs);

      container.exec({
        Cmd: ['/bin/sh', '-c', command],
        AttachStdout: true,
        AttachStderr: true
      }, (err, exec) => {
        clearTimeout(timer);
        if (err) reject(err);
        else resolve({ exitCode: 0, stdout: '', stderr: '' });
      });
    });
  }
}
```

