```typescript
// src/vm/memory-access-control.ts
interface AllowedMemoryRange {
  start: number;
  end: number;
  type: 'user' | 'heap' | 'stack';
  readable: boolean;
  writable: boolean;
}

class MemoryAccessControl {
  private allowedRanges: AllowedMemoryRange[] = [];
  private accessLog: AccessLogEntry[] = [];

  constructor(private userId: string) {
    // 사용자 메모리 범위만 허용
    this.allowedRanges = [
      {
        start: USER_MEMORY_START,
        end: USER_MEMORY_END,
        type: 'user',
        readable: true,
        writable: true
      },
      // 스택 디버깅: 제한된 범위만
      {
        start: DEBUG_STACK_START,
        end: DEBUG_STACK_END,
        type: 'stack',
        readable: true,
        writable: false  // 읽기만 가능
      }
    ];
  }

  readMemory(address: number, size: number): Buffer {
    if (!this.canAccess('read', address, size)) {
      this.logAbuseAttempt('read', address, size);
      throw new SecurityError('Memory read denied');
    }

    this.logAccess('read', address, size);
    return this.getMemory(address, size);
  }

  writeMemory(address: number, data: Buffer): void {
    if (!this.canAccess('write', address, data.length)) {
      this.logAbuseAttempt('write', address, data.length);
      throw new SecurityError('Memory write denied');
    }

    this.logAccess('write', address, data.length);
    this.setMemory(address, data);
  }

  private canAccess(
    type: 'read' | 'write',
    address: number,
    size: number
  ): boolean {
    for (const range of this.allowedRanges) {
      if (address >= range.start && address + size <= range.end) {
        if (type === 'read' && !range.readable) return false;
        if (type === 'write' && !range.writable) return false;
        return true;
      }
    }
    return false;
  }

  private logAccess(type: string, address: number, size: number): void {
    this.accessLog.push({
      timestamp: Date.now(),
      type,
      address,
      size,
      userId: this.userId
    });
  }

  private logAbuseAttempt(type: string, address: number, size: number): void {
    const entry: AbuseLogEntry = {
      timestamp: Date.now(),
      type,
      address,
      size,
      userId: this.userId,
      severity: 'HIGH'
    };

    // 데이터베이스에 저장
    this.saveAbuseLog(entry);

    // 임계값 초과 시 차단
    if (this.countAbuseAttemptsInLast5Min() > 5) {
      this.blockUser(this.userId);
    }
  }
}
```

