```typescript
// src/security/anomaly-detection.ts
class MemoryAccessAnomalyDetector {
  private baselineAccessPatterns: Map<string, AccessStatistics> = new Map();

  analyzeAndDetect(accessLog: AccessLogEntry[]): AnomalyAlert[] {
    const alerts: AnomalyAlert[] = [];

    for (const entry of accessLog) {
      const key = `${entry.type}-${Math.floor(entry.address / 1000)}`;
      const baseline = this.baselineAccessPatterns.get(key);

      if (!baseline) {
        this.baselineAccessPatterns.set(key, this.createBaseline(entry));
        continue;
      }

      // Z-score를 이용한 이상치 탐지
      const zScore = this.calculateZScore(entry.size, baseline);
      if (Math.abs(zScore) > 3.0) {  // 99.7% 신뢰도
        alerts.push({
          userId: entry.userId,
          type: 'abnormal_memory_access',
          severity: zScore > 5.0 ? 'CRITICAL' : 'HIGH',
          details: entry
        });
      }
    }

    return alerts;
  }

  private calculateZScore(value: number, baseline: AccessStatistics): number {
    return (value - baseline.mean) / baseline.stdDev;
  }
}
