// src/websocket/secure-websocket.ts
class SecureWebSocketServer {
  async handleConnection(socket: WebSocket, request: http.IncomingMessage) {
    // 1. HTTPS 강제 (WSS)
    if (!request.secure) {
      socket.close(1008, 'HTTPS required');
      return;
    }

    // 2. 토큰 검증
    const token = this.extractToken(request);
    if (!token || !this.verifyToken(token)) {
      socket.close(1008, 'Invalid or missing token');
      return;
    }

    // 3. 세션 생성
    const session = this.createSession(token);

    // 4. 메시지 핸들러
    socket.on('message', (data: Buffer) => {
      try {
        // 4.1 크기 제한
        if (data.length > MAX_MESSAGE_SIZE) {
          socket.close(1009, 'Message too large');
          return;
        }

        // 4.2 메시지 검증
        const message = this.validateMessage(data);
        if (!message) {
          socket.close(1008, 'Invalid message format');
          return;
        }

        // 4.3 권한 검증
        if (!this.hasPermission(session, message.action)) {
          socket.close(1008, 'Insufficient permissions');
          return;
        }

        // 4.4 처리
        this.handleMessage(session, message);
      } catch (error) {
        this.logSecurityEvent('websocket_error', error);
        socket.close(1011, 'Internal server error');
      }
    });

    // 5. 타임아웃 처리
    const timeout = setInterval(() => {
      if (!this.isSessionAlive(session)) {
        socket.close(1000, 'Session timeout');
        clearInterval(timeout);
      }
    }, SESSION_TIMEOUT_CHECK_MS);
  }

  private validateMessage(data: Buffer): ValidatedMessage | null {
    try {
      const json = JSON.parse(data.toString());

      // 필드 검증
      if (!json.action || typeof json.action !== 'string') return null;
      if (json.action.length > MAX_ACTION_LENGTH) return null;

      return { action: json.action, payload: json.payload || {} };
    } catch {
      return null;
    }
  }
}
```

