**Step 1: 학습 데이터 검증**
```typescript
// src/security/training-data-validator.ts
import { z } from 'zod';

// 훈련 데이터 스키마
const TrainingDataSchema = z.object({
  input: z.string()
    .min(1)
    .max(10000)
    .describe('Input code sample'),
  output: z.string()
    .min(1)
    .max(10000)
    .describe('Expected output'),
  metadata: z.object({
    source: z.enum(['verified', 'community', 'internal']),
    timestamp: z.number().int(),
    author: z.string()
  }).optional()
});

type TrainingData = z.infer<typeof TrainingDataSchema>;

class TrainingDataValidator {
  private anomalyDetector: AnomalyDetector;

  async validateBatch(batch: any[]): Promise<TrainingData[]> {
    const validated: TrainingData[] = [];

    for (const item of batch) {
      try {
        // 1. 스키마 검증
        const parsed = TrainingDataSchema.parse(item);

        // 2. 이상치 탐지
        const anomalyScore = await this.anomalyDetector.detect(parsed);
        if (anomalyScore > ANOMALY_THRESHOLD) {
          console.warn(`Suspicious sample detected (score: ${anomalyScore}):`, parsed);
          // 로깅하지만 버리지 않음 (검토용)
          continue;
        }

        // 3. 통계적 검증
        if (!this.isStatisticallyValid(parsed)) {
          console.warn(`Statistically invalid sample:`, parsed);
          continue;
        }

        // 4. 의존성 순환 검사
        if (this.hasCircularDependency(parsed)) {
          console.warn(`Circular dependency detected:`, parsed);
          continue;
        }

        validated.push(parsed);
      } catch (error) {
        console.error(`Invalid training sample:`, error);
      }
    }

    return validated;
  }

  private isStatisticallyValid(data: TrainingData): boolean {
    // 입력-출력 길이 비율 확인
    const ratio = data.output.length / data.input.length;
    if (ratio < 0.5 || ratio > 3.0) {
      return false;  // 비정상적인 비율
    }

    // 문법 검증 (간단한 파서)
    try {
      this.parseAndValidateSyntax(data.input);
      this.parseAndValidateSyntax(data.output);
      return true;
    } catch {
      return false;
    }
  }

  private hasCircularDependency(data: TrainingData): boolean {
    // 출력이 입력과 동일한 경우 순환 가능성
    if (data.output === data.input) return true;

    // 출력에 악의적 패턴이 있는지 확인
    const maliciousPatterns = [
      /system\s*\(/,
      /exec\s*\(/,
      /rm\s+-rf/,
      /fork\s*\(/
    ];

    return maliciousPatterns.some(p => p.test(data.output));
  }
}
```

