```typescript
// src/security/model-integrity.ts
import crypto from 'crypto';

interface ModelMetadata {
  version: string;
  hash: string;      // SHA-256
  signature: string; // RSA-2048 서명
  timestamp: number;
  buildInfo: {
    compiler: string;
    compiledAt: number;
    trainingDataHash: string;
  };
}

class ModelIntegrityManager {
  private privateKey: crypto.KeyObject;
  private publicKey: crypto.KeyObject;
  private modelRegistry: Map<string, ModelMetadata> = new Map();

  // 모델 서명 (빌드 시)
  signModel(modelBuffer: Buffer, version: string): ModelMetadata {
    const hash = crypto
      .createHash('sha256')
      .update(modelBuffer)
      .digest('hex');

    // RSA 서명
    const signature = crypto
      .createSign('sha256')
      .update(modelBuffer)
      .sign(this.privateKey, 'hex');

    const metadata: ModelMetadata = {
      version,
      hash,
      signature,
      timestamp: Date.now(),
      buildInfo: {
        compiler: process.version,
        compiledAt: Date.now(),
        trainingDataHash: this.getTrainingDataHash()
      }
    };

    // 메타데이터도 서명
    this.modelRegistry.set(version, metadata);

    // 영구 저장소에 기록
    this.persistMetadata(version, metadata);

    return metadata;
  }

  // 모델 검증 (로드 시)
  verifyModel(modelBuffer: Buffer, metadata: ModelMetadata): boolean {
    // 1. 해시 검증
    const calculatedHash = crypto
      .createHash('sha256')
      .update(modelBuffer)
      .digest('hex');

    if (calculatedHash !== metadata.hash) {
      console.error('Model hash mismatch!');
      return false;
    }

    // 2. 디지털 서명 검증
    const isValid = crypto
      .createVerify('sha256')
      .update(modelBuffer)
      .verify(this.publicKey, metadata.signature, 'hex');

    if (!isValid) {
      console.error('Model signature verification failed!');
      return false;
    }

    // 3. 타임스탐프 검증 (5년 이상 된 모델 거부)
    const age = Date.now() - metadata.timestamp;
    if (age > 5 * 365 * 24 * 60 * 60 * 1000) {
      console.warn('Model is too old');
      return false;
    }

    return true;
  }

  // 모델 버전 관리
  getModelMetadata(version: string): ModelMetadata | null {
    return this.modelRegistry.get(version) || null;
  }

  listAllModels(): { version: string; timestamp: number; hash: string }[] {
    return Array.from(this.modelRegistry.values()).map(m => ({
      version: m.version,
      timestamp: m.timestamp,
      hash: m.hash.substring(0, 8) + '...'
    }));
  }

  private getTrainingDataHash(): string {
    // 훈련 데이터의 SHA-256 해시
    // (실제로는 모든 훈련 샘플의 해시 병합)
    return crypto
      .createHash('sha256')
      .update(this.getTrainingDataContent())
      .digest('hex');
  }

  private persistMetadata(version: string, metadata: ModelMetadata): void {
    // 데이터베이스나 안전한 저장소에 저장
    const filePath = `./model-registry/${version}-metadata.json`;
    fs.writeFileSync(filePath, JSON.stringify(metadata, null, 2), {
      mode: 0o400  // 읽기 전용
    });
  }
}
```

