```typescript
// src/models/model-manager.ts
interface ModelEnvironment {
  production: {
    model: Model;
    metadata: ModelMetadata;
    locked: boolean;  // 수정 불가
  };
  staging: {
    model: Model;
    metadata: ModelMetadata;
    testResults: TestResult[];
  };
  rollback: {
    model: Model;
    metadata: ModelMetadata;
  };
}

class ModelManager {
  private environments: ModelEnvironment = {
    production: { model: null, metadata: null, locked: true },
    staging: { model: null, metadata: null, testResults: [] },
    rollback: { model: null, metadata: null }
  };

  // 새로운 모델을 staging에 배포
  async deployToStaging(newModel: Model): Promise<void> {
    console.log('Deploying to staging...');

    // 이전 모델을 rollback으로 백업
    if (this.environments.staging.model) {
      this.environments.rollback = {
        model: this.environments.staging.model,
        metadata: this.environments.staging.metadata
      };
    }

    this.environments.staging = {
      model: newModel,
      metadata: await this.integrityManager.signModel(
        newModel.serialize(),
        newModel.version
      ),
      testResults: []
    };
  }

  // Staging 환경에서 테스트
  async runStagingTests(): Promise<TestResult[]> {
    console.log('Running staging tests...');

    const tests = [
      this.testAccuracy(),
      this.testPerformance(),
      this.testBackwardCompatibility(),
      this.testSecurityRegression()
    ];

    const results = await Promise.all(tests);
    this.environments.staging.testResults = results;

    return results;
  }

  // 모든 테스트 통과 시 production으로 승격
  async promoteToProduction(): Promise<void> {
    const results = this.environments.staging.testResults;

    // 모든 테스트 통과 확인
    if (!results.every(r => r.passed)) {
      throw new Error('Staging tests failed, cannot promote');
    }

    console.log('Promoting to production...');

    this.environments.production = {
      model: this.environments.staging.model,
      metadata: this.environments.staging.metadata,
      locked: true  // 프로덕션은 잠금
    };

    // 감사 로그
    this.auditLog({
      action: 'promote_to_production',
      timestamp: Date.now(),
      modelVersion: this.environments.production.metadata.version
    });
  }

  // 문제 발생 시 이전 버전으로 롤백
  async rollbackToLastVersion(): Promise<void> {
    if (!this.environments.rollback.model) {
      throw new Error('No rollback version available');
    }

    console.warn('Rolling back to previous version...');

    this.environments.production = {
      model: this.environments.rollback.model,
      metadata: this.environments.rollback.metadata,
      locked: true
    };

    // 감사 로그
    this.auditLog({
      action: 'rollback_from_production',
      timestamp: Date.now(),
      modelVersion: this.environments.production.metadata.version
    });
  }

  // 모니터링: 성능 메트릭 추적
  async monitorProduction(): Promise<void> {
    setInterval(async () => {
      const metrics = await this.collectMetrics();

      // 이상 탐지
      const anomalies = this.detectAnomalies(metrics);
      if (anomalies.length > 0) {
        console.error('Performance anomalies detected:', anomalies);

        // 자동 롤백 고려
        if (this.isCritical(anomalies)) {
          await this.rollbackToLastVersion();
        }
      }
    }, 60000);  // 1분마다
  }

  private getProductionModel(): Model {
    if (!this.environments.production.locked) {
      throw new Error('Production model is not locked');
    }
    return this.environments.production.model;
  }
}
