class DataMasker {
  private sensitivePatterns = [
    { pattern: /password/i, mask: '****' },
    { pattern: /api_key|token/i, mask: '[REDACTED]' },
    { pattern: /credit_card|ssn/i, mask: '[MASKED]' }
  ];

  maskObservabilityData(data: ObservabilityData): ObservabilityData {
