      ...data,
      variables: data.variables.map(v => ({
        ...v,
        value: this.maskValue(v.name, v.value)
      }))
    };
  }

  private maskValue(name: string, value: any): any {
    for (const { pattern, mask } of this.sensitivePatterns) {
      if (pattern.test(name)) {
        return mask;
      }
    }
    return value;
  }
}
