#### 수정 방안

```typescript
// ✅ 안전한 코드 (이후)
import { spawnSync } from 'child_process';
import path from 'path';

class SafeCompiler {
  private sanitizeName(name: string): string {
    // 파일명에서 위험한 문자 제거
    if (!/^[a-zA-Z0-9_-]+$/.test(name)) {
      throw new Error('Invalid filename');
    }
    return name;
  }

  compile(cCode: string, name: string): CompileResult {
    try {
      // 1. 파일명 검증
      const safeName = this.sanitizeName(name);
      const cPath = path.join(this.outDir, `${safeName}.c`);
      const binPath = path.join(this.outDir, safeName);

      // 2. 파일 안전하게 저장
      writeFileSync(cPath, cCode);

      // 3. spawnSync 사용 (쉘 우회)
      const result = spawnSync('gcc', [
        '-O2',
        '-o', binPath,
        cPath,
        '-lm'
      ], {
        encoding: 'utf-8',
        timeout: 10000,
        stdio: ['pipe', 'pipe', 'pipe'],
        shell: false,  // 중요: 쉘 인터프리터 비활성화
        maxBuffer: 10 * 1024 * 1024
      });

      // 4. 결과 검증
      if (result.error) {
        return { ok: false, error: result.error.message };
      }

      if (result.status !== 0) {
        return {
          ok: false,
          error: result.stderr?.toString() || 'Compilation failed'
        };
      }

      return { ok: true, binaryPath: binPath };

    } catch (error) {
      return { ok: false, error: String(error) };
    }
  }

  execute(binPath: string): ExecuteResult {
    // 파일 존재 확인
    if (!fs.existsSync(binPath)) {
      return { ok: false, error: 'Binary not found' };
    }

    // spawnSync로 실행
    const result = spawnSync(binPath, [], {
      encoding: 'utf-8',
      timeout: 5000,
      stdio: ['pipe', 'pipe', 'pipe'],
      shell: false
    });

    return {
      ok: result.status === 0,
      stdout: result.stdout || '',
      stderr: result.stderr || ''
    };
  }
}
