#### 수정 방안

```typescript
// ✅ 안전한 코드 (이후)
class SafeKpmWrapper {
  private readonly kpmBinary: string;

  async search(query: string, options?: SearchOptions): Promise<SearchResult[]> {
    // 쿼리 검증
    if (!this.validateQuery(query)) {
      throw new Error('Invalid search query');
    }

    // 배열로 인자 전달
    const args = ['search', query];
    if (options?.limit) {
      args.push('--limit', String(options.limit));
    }

    return await this.executeCommand(args);
  }

  async install(packageName: string, version?: string): Promise<InstallResult> {
    // 패키지명 검증
    if (!this.validatePackageName(packageName)) {
      throw new Error('Invalid package name');
    }

    const args = ['install', packageName];
    if (version) {
      args.push(`@${version}`);
    }

    return await this.executeCommand(args);
  }

  private async executeCommand(args: string[]): Promise<any> {
    // spawnSync로 실행 (배열 기반 인자)
    const result = spawnSync('node', [this.kpmBinary, ...args], {
      encoding: 'utf-8',
      timeout: 30000,
      stdio: ['pipe', 'pipe', 'pipe'],
      shell: false  // 중요!
    });

    if (result.error) {
      throw new Error(`KPM execution failed: ${result.error.message}`);
    }

    if (result.status !== 0) {
      throw new Error(`KPM error: ${result.stderr}`);
    }

    return JSON.parse(result.stdout || '{}');
  }

  private validateQuery(query: string): boolean {
    // 길이 제한
    if (query.length > 1000) return false;

    // 위험한 패턴 차단
    const dangerous = [';', '|', '&', '`', '$', '(', ')'];
    if (dangerous.some(ch => query.includes(ch))) {
      return false;
    }

    return true;
  }

  private validatePackageName(name: string): boolean {
    // NPM 패키지명 규칙: @scope/name 형식
    const pattern = /^(@[a-z0-9-]+\/)?[a-z0-9-]+$/i;
    return pattern.test(name) && name.length <= 214;
  }
}
```

