    try {
      req.body = schema.parse(req.body);
      next();
    } catch (error) {
      if (error instanceof z.ZodError) {
        res.status(400).json({
          error: 'Invalid input',
          details: error.errors
        });
      } else {
        res.status(500).json({ error: 'Internal error' });
      }
    }
  };
}

