## 🔴 수정된 CRITICAL 취약점 (2개)

### 1. CORS (Cross-Origin Resource Sharing) 정책

#### 문제점
- Origin 검증 부재
- Wildcard (`*`) 무분별 사용 가능
- 자격증명 공개 위험
- Preflight 요청 미처리

#### 수정 방안

**Step 1: CORS 화이트리스트 설정**
```typescript
// src/middleware/cors-middleware.ts
interface CorsConfig {
  allowedOrigins: string[];
  credentials: boolean;
  maxAge: number;
  allowedMethods: string[];
  allowedHeaders: string[];
}

class CorsMiddleware {
  constructor(private config: CorsConfig) {
    // 환경변수에서 허용 origin 로드
    if (!config.allowedOrigins || config.allowedOrigins.length === 0) {
      throw new Error('No CORS origins configured');
    }
  }

  handle(req: Request, res: Response, next: NextFunction): void {
    const origin = req.headers.origin;

    // 1. Origin 엄격 검증 (화이트리스트)
    if (!this.isOriginAllowed(origin)) {
      // 허용되지 않는 origin → CORS 헤더 전송 안 함
      // 브라우저가 요청 차단
      if (req.method === 'OPTIONS') {
        res.status(403).json({ error: 'CORS not allowed for this origin' });
      }
      // CORS 헤더 없이 계속 진행 (브라우저가 차단)
      next();
      return;
    }

    // 2. CORS 헤더 설정 (허용된 origin만)
    res.setHeader('Access-Control-Allow-Origin', origin);

    // 3. 자격증명 처리
    if (this.config.credentials) {
      res.setHeader('Access-Control-Allow-Credentials', 'true');
      // 중요: credentials=true일 때는 wildcard 불가
      // Access-Control-Allow-Origin: * (금지)
      // Access-Control-Allow-Origin: https://allowed.com (필수)
    }

    // 4. Preflight 캐싱 제한 (너무 길면 정책 변경 감지 어려움)
    res.setHeader('Access-Control-Max-Age', String(this.config.maxAge));  // 3600초 (1시간)

    // 5. 메서드 제한
    res.setHeader('Access-Control-Allow-Methods', this.config.allowedMethods.join(', '));

    // 6. 헤더 제한
    res.setHeader('Access-Control-Allow-Headers', this.config.allowedHeaders.join(', '));

    // 7. 민감한 헤더 제한
    res.setHeader('Access-Control-Expose-Headers', '');  // 노출할 헤더 명시

    // Preflight 요청 처리
    if (req.method === 'OPTIONS') {
      res.status(204).end();
      return;
    }

    next();
  }

  private isOriginAllowed(origin: string | undefined): boolean {
    if (!origin) return false;

    // 정확한 매칭 (와일드카드 없음)
    return this.config.allowedOrigins.includes(origin);
  }
}

// 사용
const corsConfig: CorsConfig = {
  allowedOrigins: [
    'https://frontend.example.com',
    'https://app.example.com',
    'https://dashboard.example.com'
    // * 절대 금지
  ],
  credentials: true,
  maxAge: 3600,
  allowedMethods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization']
};

app.use(new CorsMiddleware(corsConfig).handle.bind(corsMiddleware));
```

**Step 2: 환경변수 관리**
```bash
