**Step 3: 설정 검증**
```typescript
// src/config/cors-validator.ts
function validateCorsConfig(config: CorsConfig): void {
  // 1. Wildcard 사용 금지
  if (config.allowedOrigins.includes('*')) {
    throw new Error('CORS wildcard (*) is not allowed');
  }

  // 2. HTTPS 강제 (production)
  if (process.env.NODE_ENV === 'production') {
    const allHttps = config.allowedOrigins.every(origin =>
      origin.startsWith('https://')
    );
    if (!allHttps) {
      throw new Error('All origins must use HTTPS in production');
    }
  }

  // 3. 최소한 하나의 origin
  if (config.allowedOrigins.length === 0) {
    throw new Error('At least one CORS origin must be configured');
  }
}
```

