### 1. 헤더 인젝션 방지

```typescript
// src/middleware/header-validation.ts
function validateHeaders(headers: Record<string, string>): Record<string, string> {
  const sanitized: Record<string, string> = {};

  for (const [key, value] of Object.entries(headers)) {
    // 1. 헤더 이름 검증
    if (!/^[a-zA-Z0-9-]+$/.test(key)) {
      console.warn(`Invalid header name: ${key}`);
      continue;
    }

    // 2. 값에서 개행/제어문자 제거
    const cleanValue = value
      .replace(/[\r\n\t]/g, '')  // \r\n\t 제거
      .trim();

    // 3. 길이 제한
    if (cleanValue.length > 8192) {
      console.warn(`Header value too long: ${key}`);
      continue;
    }

    sanitized[key] = cleanValue;
  }

  return sanitized;
}

// 사용
res.headers = validateHeaders(res.headers);
```

### 2. CSRF 방어

```typescript
// src/middleware/csrf-middleware.ts
class CsrfMiddleware {
  handle(req: Request, res: Response, next: NextFunction): void {
    // 1. SameSite 쿠키 설정
    res.setHeader('Set-Cookie', [
      `sessionId=${req.session.id}; HttpOnly; Secure; SameSite=Strict; Max-Age=3600`
    ]);

    // 2. CSRF 토큰 생성 (GET 요청)
    if (req.method === 'GET') {
      const token = crypto.randomBytes(32).toString('hex');
      res.locals.csrfToken = token;
      // 세션에 저장
      req.session.csrfToken = token;
    }

    // 3. CSRF 토큰 검증 (POST/PUT/DELETE)
    if (['POST', 'PUT', 'DELETE', 'PATCH'].includes(req.method)) {
      const token = req.body._csrf || req.headers['x-csrf-token'];

      if (!token || token !== req.session.csrfToken) {
        res.status(403).json({ error: 'CSRF token validation failed' });
        return;
      }
    }

    next();
  }
}
```

